1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	interface Item {
5	  type: string;
6	  material?: string;
7	  enchantment?: number;
8	  cursed?: boolean;
9	}
10	
11	interface QuoteStep {
12	  op: "quote";
13	  items: Item[];
14	}
15	
16	interface Scenario {
17	  customer: { yearsWithMHPCO: number };
18	  steps: QuoteStep[];
19	}
20	
21	interface QuoteResult {
22	  premium: number;
23	}
24	
25	const COMPONENT_BASE_PREMIUM = 25;
26	
27	const BASE_PREMIUMS: Record<string, number> = {
28	  sword: 100,
29	  amulet: 60,
30	  staff: 80,
31	  potion: 40,
32	  rune: COMPONENT_BASE_PREMIUM,
33	  moonstone: COMPONENT_BASE_PREMIUM,
34	};
35	
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	const BLOCK_SIZE = 3;
38	const BLOCK_PREMIUM = 60;
39	
40	const formsBlock = (type: string, count: number): boolean =>
41	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
42	
43	const typeBasePremium = (type: string, count: number): number => {
44	  if (formsBlock(type, count)) return BLOCK_PREMIUM;
45	  return count * BASE_PREMIUMS[type];
46	};
47	
48	const policyBasePremium = (items: Item[]): number => {
49	  const counts = new Map<string, number>();
50	  for (const item of items) {
51	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
52	  }
53	  return [...counts].reduce(
54	    (base, [type, count]) => base + typeBasePremium(type, count),
55	    0,
56	  );
57	};
58	
59	const CURSE_SURCHARGE = 0.5;
60	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
61	const HIGH_ENCHANTMENT_THRESHOLD = 5;
62	
63	const itemSurcharge = (item: Item): number => {
64	  const base = BASE_PREMIUMS[item.type];
65	  let rate = 0;
66	  if (item.cursed) rate += CURSE_SURCHARGE;
67	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) rate += HIGH_ENCHANTMENT_SURCHARGE;
68	  return rate * base;
69	};
70	
71	const itemSurcharges = (items: Item[]): number =>
72	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
73	
74	// Premiums round up (in the MHPCO's favor); toFixed guards against
75	// floating-point error nudging an exact value over an integer boundary.
76	const roundUpPremium = (amount: number): number =>
77	  Math.ceil(Number(amount.toFixed(6)));
78	
79	const quotePremium = (step: QuoteStep): number => {
80	  const { items } = step;
81	  const policyBase = policyBasePremium(items);
82	  const total =
83	    policyBase +
84	    itemSurcharges(items) +
85	    policyBase * FIRST_INSURANCE_SURCHARGE +
86	    PROCESSING_FEE;
87	  return roundUpPremium(total);
88	};
89	
90	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
91	  return { results: scenario.steps.map((step) => ({ premium: quotePremium(step) })) };
92	};
